from datetime import datetime
from typing import List, Optional, Dict, Any
import secrets
import string

from sqlalchemy.orm import Session
from sqlalchemy import or_

from app.models.user import User, Role
from app.schemas.user import UserCreate, UserUpdate
from app.utils.security import get_password_hash


def get_user(db: Session, user_id: str) -> Optional[User]:
    """
    通过ID获取用户
    
    参数:
        db (Session): 数据库会话
        user_id (str): 用户ID
    
    返回:
        Optional[User]: 用户对象或None
    """
    return db.query(User).filter(User.id == user_id).first()


def get_users(
    db: Session, 
    skip: int = 0, 
    limit: int = 100,
    username: Optional[str] = None,
    name: Optional[str] = None,
    role: Optional[str] = None,
    status: Optional[str] = None,
    current_user: Optional[User] = None
) -> List[User]:
    """
    获取用户列表，支持过滤
    
    参数:
        db (Session): 数据库会话
        skip (int): 跳过的记录数
        limit (int): 限制返回的记录数
        username (Optional[str]): 按用户名过滤
        name (Optional[str]): 按姓名过滤
        role (Optional[str]): 按角色过滤
        status (Optional[str]): 按状态过滤
        current_user (Optional[User]): 当前用户，用于部门权限控制
    
    返回:
        List[User]: 用户列表
    """
    query = db.query(User)
    
    # 应用部门权限控制
    # 如果不是admin角色，只能查看本部门用户
    if current_user and current_user.role != "admin":
        query = query.filter(User.department == current_user.department)
    
    # 应用过滤条件
    if username:
        query = query.filter(User.username.ilike(f"%{username}%"))
    if name:
        query = query.filter(User.name.ilike(f"%{name}%"))
    if role:
        query = query.filter(User.role == role)
    if status:
        query = query.filter(User.status == status)
    
    # 应用分页
    return query.offset(skip).limit(limit).all()


def create_user(db: Session, user_in: UserCreate) -> User:
    """
    创建新用户
    
    参数:
        db (Session): 数据库会话
        user_in (UserCreate): 用户创建模式
    
    返回:
        User: 创建的用户
    """
    # 创建新用户对象
    db_user = User(
        username=user_in.username,
        name=user_in.name,
        email=user_in.email,
        phone=user_in.phone,
        role=user_in.role,
        department=user_in.department,
        position=user_in.position,
        avatar=user_in.avatar,
        hashed_password=get_password_hash(user_in.password)
    )
    
    # 添加到数据库
    db.add(db_user)
    db.commit()
    db.refresh(db_user)
    
    return db_user


def update_user(db: Session, user: User, user_in: UserUpdate) -> User:
    """
    更新用户信息
    
    参数:
        db (Session): 数据库会话
        user (User): 要更新的用户
        user_in (UserUpdate): 用户更新模式
    
    返回:
        User: 更新后的用户
    """
    # 获取更新数据
    update_data = user_in.dict(exclude_unset=True)
    
    # 如果有密码更新，则哈希处理
    if "password" in update_data and update_data["password"]:
        hashed_password = get_password_hash(update_data["password"])
        del update_data["password"]
        update_data["hashed_password"] = hashed_password
    
    # 更新模型属性
    for field, value in update_data.items():
        if hasattr(user, field) and value is not None:
            setattr(user, field, value)
    
    db.add(user)
    db.commit()
    db.refresh(user)
    
    return user


def delete_user(db: Session, user_id: str) -> None:
    """
    删除用户
    
    参数:
        db (Session): 数据库会话
        user_id (str): 用户ID
    """
    user = get_user(db, user_id)
    if user:
        db.delete(user)
        db.commit()


def update_user_last_login(db: Session, user: User) -> User:
    """
    更新用户最后登录时间
    
    参数:
        db (Session): 数据库会话
        user (User): 用户对象
    
    返回:
        User: 更新后的用户
    """
    user.last_login = datetime.utcnow()
    db.add(user)
    db.commit()
    db.refresh(user)
    
    return user


def reset_user_password(db: Session, user: User) -> str:
    """
    重置用户密码
    
    参数:
        db (Session): 数据库会话
        user (User): 用户对象
    
    返回:
        str: 临时密码
    """
    # 生成随机密码
    alphabet = string.ascii_letters + string.digits
    temp_password = ''.join(secrets.choice(alphabet) for _ in range(8))
    
    # 更新用户密码
    user.hashed_password = get_password_hash(temp_password)
    db.add(user)
    db.commit()
    
    return temp_password


def get_role(db: Session, role_id: int) -> Optional[Role]:
    """
    通过ID获取角色
    
    参数:
        db (Session): 数据库会话
        role_id (int): 角色ID
    
    返回:
        Optional[Role]: 角色对象或None
    """
    return db.query(Role).filter(Role.id == role_id).first()


def get_role_by_value(db: Session, value: str) -> Optional[Role]:
    """
    通过值获取角色
    
    参数:
        db (Session): 数据库会话
        value (str): 角色值
    
    返回:
        Optional[Role]: 角色对象或None
    """
    return db.query(Role).filter(Role.value == value).first()


def get_roles(db: Session) -> List[Role]:
    """
    获取所有角色
    
    参数:
        db (Session): 数据库会话
    
    返回:
        List[Role]: 角色列表
    """
    return db.query(Role).all()


def create_initial_roles(db: Session) -> None:
    """
    创建初始角色
    
    参数:
        db (Session): 数据库会话
    """
    roles = [
        {"name": "管理员", "value": "admin", "description": "系统管理员，拥有所有权限"},
        {"name": "操作员", "value": "operator", "description": "系统操作人员，可以管理模型、知识库和智能体"},
        {"name": "普通用户", "value": "user", "description": "普通用户，仅可使用智能体"},
        {"name": "访客", "value": "guest", "description": "访客，只有有限的查看权限"}
    ]
    
    for role_data in roles:
        # 检查角色是否已存在
        existing_role = get_role_by_value(db, role_data["value"])
        if not existing_role:
            role = Role(**role_data)
            db.add(role)
    
    db.commit()


def create_admin_user(db: Session, password: str = "admin123") -> None:
    """
    创建管理员用户
    
    参数:
        db (Session): 数据库会话
        password (str): 管理员密码
    """
    # 检查是否已存在管理员
    admin = db.query(User).filter(User.username == "admin").first()
    if not admin:
        admin_user = User(
            username="admin",
            name="系统管理员",
            email="admin@example.com",
            phone="13800000000",
            role="admin",
            avatar="data:image/png;base64,",
            status="active",
            department="技术部",
            position="系统管理员",
            hashed_password=get_password_hash(password)
        )
        db.add(admin_user)
        db.commit() 


def count_users(
    db: Session, 
    username: Optional[str] = None,
    name: Optional[str] = None,
    role: Optional[str] = None,
    status: Optional[str] = None,
    current_user: Optional[User] = None
) -> int:
    """
    计算用户总数，支持过滤
    
    参数:
        db (Session): 数据库会话
        username (Optional[str]): 按用户名过滤
        name (Optional[str]): 按姓名过滤
        role (Optional[str]): 按角色过滤
        status (Optional[str]): 按状态过滤
        current_user (Optional[User]): 当前用户，用于部门权限控制
    
    返回:
        int: 符合条件的用户总数
    """
    query = db.query(User)
    
    # 应用部门权限控制
    # 如果不是admin角色，只能查看本部门用户
    if current_user and current_user.role != "admin":
        query = query.filter(User.department == current_user.department)
    
    # 应用过滤条件
    if username:
        query = query.filter(User.username.ilike(f"%{username}%"))
    if name:
        query = query.filter(User.name.ilike(f"%{name}%"))
    if role:
        query = query.filter(User.role == role)
    if status:
        query = query.filter(User.status == status)
    
    return query.count()